#!/usr/bin/env python3
"""Dump last-2-days hackathon Claude Code sessions into the repo.

Raw JSONL copy + readable Markdown, main sessions only (no subagents).
"""
import json, os, shutil, time, glob

PROJECTS_ROOT = "/home/delus/.claude/projects"
REPO = "/home/delus/Documents/code/hackathon/dqplus-hackathon-2026"
OUT = os.path.join(REPO, "session-logs")
CUTOFF = time.time() - 2 * 86400  # last 2 days
PREFIX = "-home-delus-Documents-code-hackathon"
MAX_BLOCK = 2000  # truncate long tool output in markdown only

def short_project(dirname):
    name = dirname[len(PREFIX):].lstrip("-")
    return name or "hackathon-root"

def trunc(s):
    s = s if isinstance(s, str) else str(s)
    if len(s) > MAX_BLOCK:
        return s[:MAX_BLOCK] + f"\n… [truncated {len(s)-MAX_BLOCK} chars — see raw .jsonl]"
    return s

def render_content(content):
    """Return list of markdown chunks for a message.content (str or list)."""
    out = []
    if isinstance(content, str):
        if content.strip():
            out.append(trunc(content))
        return out
    if not isinstance(content, list):
        return out
    for b in content:
        if not isinstance(b, dict):
            continue
        t = b.get("type")
        if t == "text":
            if b.get("text", "").strip():
                out.append(trunc(b["text"]))
        elif t == "thinking":
            th = b.get("thinking", "").strip()
            if th:
                out.append("<details><summary>💭 thinking</summary>\n\n" + trunc(th) + "\n\n</details>")
        elif t == "tool_use":
            inp = json.dumps(b.get("input", {}), ensure_ascii=False)
            out.append(f"🔧 **{b.get('name','tool')}** → `{trunc(inp)}`")
        elif t == "tool_result":
            c = b.get("content", "")
            if isinstance(c, list):
                c = "\n".join(x.get("text", "") for x in c if isinstance(x, dict) and x.get("type") == "text")
            c = (c or "").strip()
            if c:
                out.append("📎 _tool result_:\n```\n" + trunc(c) + "\n```")
        elif t == "image":
            out.append("🖼️ _(image omitted — see raw .jsonl)_")
    return out

def to_markdown(jsonl_path, project, session_id):
    lines = []
    first_ts = last_ts = None
    with open(jsonl_path, encoding="utf-8") as f:
        for raw in f:
            raw = raw.strip()
            if not raw:
                continue
            try:
                e = json.loads(raw)
            except Exception:
                continue
            typ = e.get("type")
            ts = e.get("timestamp", "")
            if ts:
                first_ts = first_ts or ts
                last_ts = ts
            if typ not in ("user", "assistant"):
                continue
            msg = e.get("message", {})
            chunks = render_content(msg.get("content"))
            if not chunks:
                continue
            role = "🧑 User" if typ == "user" else "🤖 Assistant"
            header = f"### {role}" + (f"  ·  _{ts}_" if ts else "")
            lines.append(header + "\n\n" + "\n\n".join(chunks))
    head = [
        f"# Session `{session_id}`",
        f"- **Project:** `{project}`",
        f"- **Span:** {first_ts or '?'} → {last_ts or '?'}",
        f"- **Source:** `{jsonl_path}`",
        "\n---\n",
    ]
    return "\n".join(head) + "\n\n" + "\n\n---\n\n".join(lines) + "\n"

def main():
    count = 0
    total_bytes = 0
    for entry in sorted(os.listdir(PROJECTS_ROOT)):
        if not entry.startswith(PREFIX):
            continue
        pdir = os.path.join(PROJECTS_ROOT, entry)
        if not os.path.isdir(pdir):
            continue
        project = short_project(entry)
        for jf in sorted(glob.glob(os.path.join(pdir, "*.jsonl"))):  # maxdepth 1 = main only
            if os.path.getmtime(jf) < CUTOFF:
                continue
            session_id = os.path.splitext(os.path.basename(jf))[0]
            dest_dir = os.path.join(OUT, project)
            os.makedirs(dest_dir, exist_ok=True)
            shutil.copyfile(jf, os.path.join(dest_dir, session_id + ".jsonl"))
            try:
                md = to_markdown(jf, project, session_id)
            except Exception as ex:
                md = f"# Session {session_id}\n\nMarkdown render failed: {ex}\n"
            with open(os.path.join(dest_dir, session_id + ".md"), "w", encoding="utf-8") as w:
                w.write(md)
            sz = os.path.getsize(jf)
            total_bytes += sz
            count += 1
            print(f"{project:35s} {session_id}  {sz//1024} KB")
    print(f"\nDumped {count} sessions, {total_bytes//1024//1024} MB raw.")

if __name__ == "__main__":
    main()

