#!/usr/bin/env python3
"""Find which current .env values were exposed in the (now-pushed) session logs.

Reads ORIGINAL unredacted transcripts, extracts secret values, then checks
.env files. Prints only masked fingerprints (prefix + length), never full secrets.
"""
import os, re, glob, hashlib

PROJECTS_ROOT = "/home/delus/.claude/projects"
PREFIX = "-home-delus-Documents-code-hackathon"
CUTOFF_DAYS = 2
ENV_ROOTS = ["/home/delus/Documents/code/hackathon"]  # where hackathon projects live

VALUE_PATTERNS = [
    re.compile(r"sk-ant-[A-Za-z0-9_-]{20,}"),
    re.compile(r"sk-proj-[A-Za-z0-9_-]{20,}"),
    re.compile(r"sk-[A-Za-z0-9]{20,}"),
    re.compile(r"AKIA[0-9A-Z]{16}"),
    re.compile(r"gh[pousr]_[A-Za-z0-9]{30,}"),
    re.compile(r"AIza[0-9A-Za-z_-]{35}"),
    re.compile(r"eyJ[A-Za-z0-9_-]{15,}\.[A-Za-z0-9_-]{15,}\.[A-Za-z0-9_-]{10,}"),
]
# assignment values (the part after = / :)
ASSIGN = re.compile(
    r'(?:api[_-]?key|secret[_-]?key|secret|access[_-]?token|auth[_-]?token|authtoken|'
    r'token|password|passwd|pwd|client[_-]?secret)["\']?\s*[:=]\s*["\']?([^\s"\'\\,}]{6,})',
    re.IGNORECASE)
PLACEHOLDER = re.compile(r"^(your[_-]?|xxx|placeholder|example|changeme|change_this|<|\$\{|REDACTED)", re.IGNORECASE)

def mask(v):
    return f"{v[:6]}…({len(v)} chars, sha1:{hashlib.sha1(v.encode()).hexdigest()[:8]})"

def extract_secrets():
    import time
    cutoff = time.time() - CUTOFF_DAYS * 86400
    found = {}  # value -> set(source session basenames)
    for entry in os.listdir(PROJECTS_ROOT):
        if not entry.startswith(PREFIX):
            continue
        for jf in glob.glob(os.path.join(PROJECTS_ROOT, entry, "*.jsonl")):
            if os.path.getmtime(jf) < cutoff:
                continue
            try:
                text = open(jf, encoding="utf-8", errors="ignore").read()
            except Exception:
                continue
            sess = os.path.basename(jf)[:8]
            for pat in VALUE_PATTERNS:
                for m in pat.findall(text):
                    found.setdefault(m, set()).add(sess)
            for m in ASSIGN.findall(text):
                if not PLACEHOLDER.match(m):
                    found.setdefault(m, set()).add(sess)
    return found

def find_env_files():
    files = []
    for root in ENV_ROOTS:
        for dp, dn, fn in os.walk(root):
            if any(x in dp for x in ("/node_modules/", "/.venv/", "/.git/", "/session-logs/")):
                continue
            for f in fn:
                if f == ".env" or f.startswith(".env.") and not f.endswith(".example"):
                    files.append(os.path.join(dp, f))
    return files

def main():
    exposed = extract_secrets()
    print(f"Distinct exposed secret values found in transcripts: {len(exposed)}\n")

    env_files = find_env_files()
    print(f".env files scanned: {len(env_files)}\n")

    hits = []
    for ef in env_files:
        try:
            for ln in open(ef, encoding="utf-8", errors="ignore"):
                ln = ln.strip()
                if not ln or ln.startswith("#") or "=" not in ln:
                    continue
                k, _, v = ln.partition("=")
                v = v.strip().strip('"').strip("'")
                if len(v) < 6 or PLACEHOLDER.match(v):
                    continue
                if v in exposed:
                    hits.append((ef, k.strip(), v, sorted(exposed[v])))
        except Exception:
            continue

    if not hits:
        print("No current .env value matches an exposed secret. ✅")
        print("(Keys may have been passed inline/CLI rather than via .env — still rotate the ones the logs showed.)")
    else:
        print("⚠️  EXPOSED KEYS STILL PRESENT IN .env — ROTATE THESE:\n")
        for ef, k, v, sess in hits:
            print(f"  {ef}")
            print(f"    {k} = {mask(v)}")
            print(f"    seen in sessions: {', '.join(sess)}\n")

    # Also summarize exposed values by type for the rotation checklist
    print("\n--- Exposed value fingerprints (for your rotation checklist) ---")
    def kind(v):
        if v.startswith("sk-ant-"): return "anthropic-key"
        if v.startswith("sk-proj-") or v.startswith("sk-"): return "openai-key"
        if v.startswith("eyJ"): return "jwt"
        if v.startswith("AKIA"): return "aws-key"
        if v.startswith(("ghp_","gho_","ghu_","ghs_","ghr_")): return "github-token"
        if v.startswith("AIza"): return "google-key"
        return "generic-secret"
    from collections import defaultdict
    by = defaultdict(list)
    for v, sess in exposed.items():
        by[kind(v)].append((v, sorted(sess)))
    for t in sorted(by):
        print(f"\n  [{t}]  ({len(by[t])})")
        for v, sess in sorted(by[t], key=lambda x: -len(x[0]))[:20]:
            print(f"    {mask(v)}   sessions: {', '.join(sess)}")

if __name__ == "__main__":
    main()

